<template>
  <i :class="`${prefixCls}-daisy`" :style="spinnerStyle"></i>
</template>

<script>
  export default {
    props: {
      prefixCls: {
        type: String,
        default: 'hmb-spinner',
      },
      size: Number,
      color: String,
    },

    computed: {
      spinnerColor() {
        return this.color || this.$parent.color || '#ccc';
      },

      spinnerSize() {
        return `${this.size || this.$parent.size || 28}px`;
      },

      spinnerStyle() {
        return {
          height: this.spinnerSize,
          width: this.spinnerSize,
        };
      },
    },
  };
</script>

<style lang="less">
  @spinnerSnakePrefixCls: hmb-spinner;
  .@{spinnerSnakePrefixCls} {
    &-daisy {
      width: 20px;
      height: 20px;
      display: inline-block;
      vertical-align: middle;
      animation: weuiLoading 1s steps(12, end) infinite;
      background: transparent url(data:image/svg+xml;base64,) no-repeat;
      -webkit-background-size: 100%;
      background-size: 100%;
    }
  }
  
  @keyframes weuiLoading {
    0% {
      -webkit-transform: rotate3d(0, 0, 1, 0deg);
    }
    100% {
      -webkit-transform: rotate3d(0, 0, 1, 360deg);
    }
  }
</style>


